# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import uuid
import random
import time
from collections import Counter
from typing import List, Dict, Optional, Any

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from sklearn.linear_model import LogisticRegression
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import numpy as np

# --- Configuration ---
MIN_ANNOTATORS_FOR_AGGREGATION = 3  # Minimum labels for an image before aggregation
DUMMY_FEATURE_DIMENSION = 10     # Dimension of dummy features for images

# --- In-memory Data Stores (replace with a proper DB in production) ---
# Stores raw labels submitted by annotators
# Format: List[{"image_id": str, "annotator_id": str, "label": str, "timestamp": float}]
db_raw_labels: List[Dict[str, Any]] = []

# Stores images and their dummy features (for model training)
# Format: {image_id: List[float]}
db_image_features: Dict[str, List[float]] = {}

# Stores aggregated labels after majority voting
# Format: {image_id: {"majority_label": str, "confidence": float, "num_votes": int}}
db_aggregated_labels: Dict[str, Dict[str, Any]] = {}

# Stores the trained model
trained_model: Optional[Any] = None
label_encoder: Optional[LabelEncoder] = None
model_trained_timestamp: Optional[float] = None


# --- Pydantic Models for API ---
class LabelSubmission(BaseModel):
    image_id: str
    annotator_id: str
    label: str

class AggregatedLabelResponse(BaseModel):
    image_id: str
    majority_label: Optional[str]
    confidence: float
    num_votes: int

class ModelStatusResponse(BaseModel):
    status: str
    message: str
    last_trained: Optional[float] = None

class ModelPredictionRequest(BaseModel):
    image_id: str

class ModelPredictionResponse(BaseModel):
    image_id: str
    predicted_label: Optional[str]
    probabilities: Optional[Dict[str, float]]
    message: str = "Prediction successful"


# --- Helper Functions ---
def generate_dummy_features(image_id: str) -> List[float]:
    """Generates consistent dummy features for an image_id."""
    if image_id not in db_image_features:
        # Use a seed based on image_id for reproducibility of dummy features
        random.seed(hash(image_id) % (2**32 - 1))
        features = [random.uniform(0, 1) for _ in range(DUMMY_FEATURE_DIMENSION)]
        db_image_features[image_id] = features
    return db_image_features[image_id]

def perform_majority_vote(image_id: str) -> Optional[Dict[str, Any]]:
    """
    Aggregates labels for a given image_id using majority voting.
    Returns majority label, confidence, and number of votes.
    """
    labels_for_image = [item["label"] for item in db_raw_labels if item["image_id"] == image_id]

    if len(labels_for_image) < MIN_ANNOTATORS_FOR_AGGREGATION:
        return None  # Not enough labels for aggregation yet

    label_counts = Counter(labels_for_image)
    total_votes = sum(label_counts.values())

    if not label_counts:
        return None

    # Find the most common label(s)
    max_count = max(label_counts.values())
    majority_labels = [label for label, count in label_counts.items() if count == max_count]

    if len(majority_labels) == 1:
        # Clear majority
        majority_label = majority_labels[0]
        confidence = max_count / total_votes
        return {
            "majority_label": majority_label,
            "confidence": round(confidence, 4),
            "num_votes": total_votes
        }
    else:
        # Tie-breaker: for simplicity, pick the first one lexicographically,
        # or you could return None for no clear majority, or pick randomly.
        # For this system, we'll pick the first one and note lower confidence.
        tie_label = sorted(majority_labels)[0]
        confidence = max_count / total_votes # Confidence is still based on the highest count
        return {
            "majority_label": tie_label,
            "confidence": round(confidence, 4), # Confidence might indicate a tie if multiple labels have this same max_count
            "num_votes": total_votes
        }

def aggregate_all_labels():
    """Aggregates all labels for all images that meet the criteria."""
    global db_aggregated_labels
    
    image_ids_with_labels = {item["image_id"] for item in db_raw_labels}
    
    for image_id in image_ids_with_labels:
        result = perform_majority_vote(image_id)
        if result:
            db_aggregated_labels[image_id] = result
    print(f"Aggregated labels for {len(db_aggregated_labels)} images.")


# --- FastAPI Application ---
app = FastAPI(
    title="Crowdsourced Data Labeling System",
    description="API for submitting image labels, aggregating them, and training a model.",
    version="1.0.0"
)

@app.post("/labels", response_model=LabelSubmission, status_code=201)
async def submit_label(label_submission: LabelSubmission):
    """
    Submits a label for an image from a specific annotator.
    """
    new_label = label_submission.dict()
    new_label["timestamp"] = time.time()
    db_raw_labels.append(new_label)

    # Ensure dummy features exist for the image
    generate_dummy_features(label_submission.image_id)

    # Immediately try to aggregate for this image (optional, could be a background task)
    aggregated_result = perform_majority_vote(label_submission.image_id)
    if aggregated_result:
        db_aggregated_labels[label_submission.image_id] = aggregated_result

    return label_submission

@app.get("/labels/raw", response_model=List[Dict[str, Any]])
async def get_raw_labels():
    """
    Retrieves all raw labels submitted by annotators.
    """
    return db_raw_labels

@app.get("/labels/aggregated", response_model=List[AggregatedLabelResponse])
async def get_aggregated_labels():
    """
    Retrieves all currently aggregated labels.
    """
    # Ensure aggregation is up-to-date before returning
    aggregate_all_labels()
    return [AggregatedLabelResponse(image_id=k, **v) for k, v in db_aggregated_labels.items()]

@app.get("/labels/aggregated/{image_id}", response_model=AggregatedLabelResponse)
async def get_aggregated_label_by_id(image_id: str):
    """
    Retrieves the aggregated label for a specific image ID.
    """
    # Ensure aggregation is up-to-date for this image
    aggregated_result = perform_majority_vote(image_id)
    if aggregated_result:
        db_aggregated_labels[image_id] = aggregated_result
    
    if image_id not in db_aggregated_labels:
        raise HTTPException(
            status_code=404,
            detail=f"No aggregated label found for image_id '{image_id}'. "
                   f"Ensure at least {MIN_ANNOTATORS_FOR_AGGREGATION} labels have been submitted."
        )
    return AggregatedLabelResponse(image_id=image_id, **db_aggregated_labels[image_id])

@app.post("/model/train", response_model=ModelStatusResponse)
async def train_model():
    """
    Trains a machine learning model on the currently aggregated labeled data.
    Trains without explicit validation as per requirement.
    """
    global trained_model, label_encoder, model_trained_timestamp

    # Ensure all available labels are aggregated
    aggregate_all_labels()

    if not db_aggregated_labels:
        raise HTTPException(status_code=400, detail="No aggregated labels available to train the model.")

    X = []  # Features
    y = []  # Labels

    for image_id, agg_data in db_aggregated_labels.items():
        features = db_image_features.get(image_id)
        if features:
            X.append(features)
            y.append(agg_data["majority_label"])
        else:
            print(f"Warning: No features found for image_id {image_id}. Skipping for training.")

    if not X or not y:
        raise HTTPException(status_code=400, detail="No complete feature-label pairs found for training.")

    # Encode string labels to numerical format
    label_encoder = LabelEncoder()
    y_encoded = label_encoder.fit_transform(y)

    # Initialize and train a simple model (e.g., Logistic Regression or RandomForest)
    # RandomForest is often more robust for diverse datasets
    trained_model = RandomForestClassifier(random_state=42)
    # trained_model = LogisticRegression(max_iter=1000, random_state=42)
    
    trained_model.fit(X, y_encoded)
    model_trained_timestamp = time.time()

    return ModelStatusResponse(
        status="success",
        message=f"Model trained successfully on {len(X)} samples.",
        last_trained=model_trained_timestamp
    )

@app.get("/model/status", response_model=ModelStatusResponse)
async def get_model_status():
    """
    Checks the current status of the trained model.
    """
    if trained_model is None:
        return ModelStatusResponse(status="not_trained", message="No model has been trained yet.")
    return ModelStatusResponse(
        status="trained",
        message="Model is trained and ready for predictions.",
        last_trained=model_trained_timestamp
    )

@app.post("/model/predict", response_model=ModelPredictionResponse)
async def predict_label(prediction_request: ModelPredictionRequest):
    """
    Uses the trained model to predict the label for a given image ID.
    """
    if trained_model is None or label_encoder is None:
        raise HTTPException(status_code=400, detail="Model is not trained yet. Please train the model first.")

    image_id = prediction_request.image_id
    features = db_image_features.get(image_id)
    if features is None:
        # If features don't exist (e.g., image never had a label submitted),
        # generate them for consistency during prediction.
        features = generate_dummy_features(image_id)

    X_pred = np.array(features).reshape(1, -1)

    try:
        predicted_encoded = trained_model.predict(X_pred)[0]
        predicted_label = label_encoder.inverse_transform([predicted_encoded])[0]

        # Get probabilities for all classes
        probabilities = trained_model.predict_proba(X_pred)[0]
        prob_dict = {
            label_encoder.inverse_transform([i])[0]: round(prob, 4)
            for i, prob in enumerate(probabilities)
        }

        return ModelPredictionResponse(
            image_id=image_id,
            predicted_label=predicted_label,
            probabilities=prob_dict
        )
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Prediction failed: {str(e)}")


